+#[test]
+fn test_compact_uses_short_keys() {
+    let raw = capabilities_raw(&["--format", "json", "--compact"]);
+    let text = String::from_utf8(raw).expect("utf8");
+    let json: Value = serde_json::from_str(text.trim()).expect("parse compact JSON");
