+/// Read JSONL log file and return parsed events.
+fn read_retention_log(log_dir: &Path) -> Vec<RetentionEvent> {
+    let entries: Vec<_> = fs::read_dir(log_dir)
+        .expect("read log dir")
+        .filter_map(|e| e.ok())
+        .filter(|e| {
+            e.path()
+                .extension()
+                .is_some_and(|ext| ext == "jsonl")
+        })
+        .collect();
+
+    let mut events = Vec::new();
+    for entry in entries {
+        let file = fs::File::open(entry.path()).expect("open log file");
+        let reader = BufReader::new(file);
+        for line in reader.lines() {
+            let line = line.expect("read line");
+            if line.trim().is_empty() {
+                continue;
+            }
+            let event: RetentionEvent =
+                serde_json::from_str(&line).expect("parse retention event");
+            events.push(event);
+        }
+    }
+    events
+}
